module register_16bit(
    input clk, 
    input reset, 
    input load, 
    input [15:0] d, 
    output reg [15:0] q);

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (reset)
            q <= 16'b0000000000000000;
        else if (load)
            q <= d;
    end
endmodule
